<div class="mx-auto" style="max-width:780px"><h1>Upload video</h1><form method="post" enctype="multipart/form-data" class="card card-body"><input type="hidden" name="csrf" value="<?= Security::e(Security::csrfToken()) ?>"><label class="form-label">Title<input class="form-control" name="title" required maxlength="180"></label><label class="form-label">Description<textarea class="form-control" name="description" rows="5"></textarea></label><label class="form-label">Tags<input class="form-control" name="tags"></label><label class="form-label">Video<input class="form-control" type="file" name="video" accept="video/mp4,video/webm,video/ogg" required></label><label class="form-label">Thumbnail<input class="form-control" type="file" name="thumbnail" accept="image/jpeg,image/png,image/webp"></label><div class="row"><div class="col"><label class="form-label">Visibility<select class="form-select" name="visibility"><option>public</option><option>private</option><option>unlisted</option></select></label></div><div class="col"><label class="form-label">Status<select class="form-select" name="status"><option>published</option><option>draft</option><option>scheduled</option></select></label></div></div><label class="form-label">Publish at<input class="form-control" type="datetime-local" name="published_at"></label><label><input type="checkbox" name="allow_download"> Allow downloads</label><label><input type="checkbox" name="allow_embed" checked> Allow embeds</label><label><input type="checkbox" name="age_restricted"> Age restricted</label><button class="btn btn-danger mt-3">Publish</button></form></div>
